@startuml
class Client {
    label "C" as icon
    text "Client"
}

class Context {
    label "C" as icon
    text "Context"
    note right of "Context" as note1
    "currentState": State
    note right of "currentState" as note2
    "request()"
}

class State {
    label "I" as icon
    text "State"
    note right of "State" as note3
    "handle()"
}

class StateOne {
    label "C" as icon
    text "StateOne"
    note right of "StateOne" as note4
    "handle()"
}

class StateTwo {
    label "C" as icon
    text "StateTwo"
    note right of "StateTwo" as note5
    "handle()"
}

Client --> Context
Context --> State
Context --> StateOne
Context --> StateTwo
StateOne --> State
StateTwo --> State

@enduml
